import{_ as a,o as s,c as t,a2 as r}from"./chunks/framework.Cuq8tsM6.js";const p=JSON.parse('{"title":"Facturation & Paiements","description":"","frontmatter":{"title":"Facturation & Paiements"},"headers":[],"relativePath":"docs/fr/faq/billing.md","filePath":"docs/fr/faq/billing.md"}'),n={name:"docs/fr/faq/billing.md"};function i(o,e,l,d,u,m){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="facturation-paiements" tabindex="-1">Facturation &amp; Paiements <a class="header-anchor" href="#facturation-paiements" aria-label="Permalink to &quot;Facturation &amp; Paiements&quot;">​</a></h1><h2 id="je-ne-vois-pas-mes-revenus-dans-mon-wallet" tabindex="-1">Je ne vois pas mes revenus dans mon Wallet <a class="header-anchor" href="#je-ne-vois-pas-mes-revenus-dans-mon-wallet" aria-label="Permalink to &quot;Je ne vois pas mes revenus dans mon Wallet&quot;">​</a></h2><p>Le crédit n&#39;est pas automatique à la signature, mais à la <strong>réalisation</strong>. Vous devez valider manuellement selon le format :</p><ul><li><strong>Insertion Colis :</strong> Avez-vous rempli votre déclaration de volume hebdomadaire ? (Le lundi ou mardi)</li><li><strong>Email :</strong> Avez-vous cliqué sur <strong>&quot;Valider la diffusion&quot;</strong> après l&#39;envoi ?</li></ul><p>Sans cette action, les fonds restent séquestrés.</p><h2 id="comment-retirer-mes-gains-et-editer-ma-facture" tabindex="-1">Comment retirer mes gains et éditer ma facture ? <a class="header-anchor" href="#comment-retirer-mes-gains-et-editer-ma-facture" aria-label="Permalink to &quot;Comment retirer mes gains et éditer ma facture ?&quot;">​</a></h2><p>Allez dans <strong>Transaction → Exchange</strong> et cliquez sur <code>Retirer</code>. Saisissez le montant.</p><p><strong>Important :</strong> Si des frais de gestion s&#39;appliquent, éditez votre facture en conséquence du montant net reçu.</p><h2 id="a-partir-de-quand-les-revenus-sont-ils-disponibles" tabindex="-1">À partir de quand les revenus sont-ils disponibles ? <a class="header-anchor" href="#a-partir-de-quand-les-revenus-sont-ils-disponibles" aria-label="Permalink to &quot;À partir de quand les revenus sont-ils disponibles ?&quot;">​</a></h2><p>Le revenu de la campagne est versé au solde de votre compte <strong>30 jours après le dernier reporting</strong>. Choisissez ensuite <code>Transférer vers le wallet</code> ou <code>Retirer</code> vos revenus.</p><h2 id="quand-sont-emis-les-paiements" tabindex="-1">Quand sont émis les paiements ? <a class="header-anchor" href="#quand-sont-emis-les-paiements" aria-label="Permalink to &quot;Quand sont émis les paiements ?&quot;">​</a></h2><p>Les paiements sont émis à <strong>30 jours fin de mois</strong>, date de réception de la demande de retrait, à condition que la facture soumise soit valide.</p><h2 id="puis-je-reinvestir-mes-gains" tabindex="-1">Puis-je réinvestir mes gains ? <a class="header-anchor" href="#puis-je-reinvestir-mes-gains" aria-label="Permalink to &quot;Puis-je réinvestir mes gains ?&quot;">​</a></h2><p>Oui, sans frais. Dans <strong>Exchange</strong>, cliquez sur <code>Transférer vers le wallet</code>. Vous pourrez utiliser ce solde immédiatement pour acheter du trafic pour votre propre site.</p>',14)])])}const f=a(n,[["render",i]]);export{p as __pageData,f as default};
